def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional function to handle the edge case for large input
def solve_large_input(nums_str, target):
    nums = list(map(int, nums_str.split(',')))
    return solve(nums, target)
